namespace WarehouseApp.Services;

public class WarehouseInfo
{
    public string Id { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
}

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single user circuit.
/// Components subscribe to OnChange to react when the selection changes.
/// </summary>
public class WarehouseState
{
    private static readonly List<WarehouseInfo> _allWarehouses =
    [
        new() { Id = "wh-1", Name = "Warehouse A" },
        new() { Id = "wh-2", Name = "Warehouse B" },
        new() { Id = "wh-3", Name = "Warehouse C" },
    ];

    public IReadOnlyList<WarehouseInfo> AvailableWarehouses => _allWarehouses;

    public WarehouseInfo CurrentWarehouse { get; private set; } = _allWarehouses[0];

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        var warehouse = _allWarehouses.FirstOrDefault(w => w.Id == warehouseId);
        if (warehouse is not null && warehouse.Id != CurrentWarehouse.Id)
        {
            CurrentWarehouse = warehouse;
            OnChange?.Invoke();
        }
    }
}

namespace WarehouseApp.Services;

/// <summary>
/// Scoped service that manages low-stock alert polling for the current circuit.
/// Fires OnAlertCountChanged when new data arrives so all subscribed components update.
/// </summary>
public class InventoryAlertService : IAsyncDisposable
{
    private readonly WarehouseState _warehouseState;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChanged;
    }

    /// <summary>
    /// Simulates a database query returning low-stock item count.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = Random.Shared.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Called by components that want polling to be active.
    /// Polling starts on first subscriber, stops when all unsubscribe.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            CancelPolling();
        }
    }

    /// <summary>
    /// Force an immediate refresh (e.g., after warehouse change).
    /// </summary>
    public async Task RefreshAsync()
    {
        var count = await GetLowStockCountAsync(_warehouseState.CurrentWarehouse.Id);
        CurrentAlertCount = count;
        OnAlertCountChanged?.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Initial fetch immediately
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (_timer is null || !await _timer.WaitForNextTickAsync(ct))
                    break;

                await RefreshAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private void HandleWarehouseChanged()
    {
        if (_subscriberCount > 0)
        {
            _ = RefreshAsync();
        }
    }

    private void CancelPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public ValueTask DisposeAsync()
    {
        _warehouseState.OnChange -= HandleWarehouseChanged;
        CancelPolling();
        return ValueTask.CompletedTask;
    }
}

