@using WarehouseApp.Services
@inject WarehouseState WarehouseState
@implements IDisposable
@rendermode InteractiveServer

<div class="warehouse-selector">
    <label for="warehouse-select"><strong>Warehouse:</strong></label>
    <select id="warehouse-select" class="form-select form-select-sm d-inline-block w-auto ms-2"
            value="@WarehouseState.CurrentWarehouse.Id"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    // Subscribe so this component re-renders if another component changes the warehouse
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleStateChanged;
    }

    private void HandleStateChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleStateChanged;
    }
}

@using WarehouseApp.Services
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<span class="badge bg-danger" title="Low stock alerts">@AlertService.CurrentAlertCount</span>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        if (_handler is not null)
        {
            AlertService.OnAlertCountChanged -= _handler;
        }
    }
}

