@page "/"
@using WarehouseApp.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p>Currently viewing: <strong>@WarehouseState.CurrentWarehouse.Name</strong></p>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Low Stock Alerts</h5>
        <p class="card-text">
            Items below minimum level:
            <span class="badge bg-danger fs-5">@AlertService.CurrentAlertCount</span>
        </p>
        <p class="text-muted small">Refreshes every 10 seconds while this page is open.</p>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;

        // Start polling when dashboard becomes visible
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        // Stop polling when user leaves the page
        AlertService.StopPolling();

        if (_warehouseHandler is not null)
            WarehouseState.OnChange -= _warehouseHandler;
        if (_alertHandler is not null)
            AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

